import React from 'react'
import { render, cleanup, waitFor } from '@testing-library/react'
import I18nProvider from './src/I18nProvider'
import DynamicNamespaces from './src/DynamicNamespaces'
import useTranslation from './src/useTranslation'

const Text = () => {
  const { t, lang } = useTranslation('common')
  return <span>{`${lang}:${t('languageName')}`}</span>
}

describe('temporary I18nProvider lang reproducer', () => {
  afterEach(() => {
    cleanup()
    delete globalThis.__NEXT_TRANSLATE__
  })

  test('DynamicNamespaces respects surrounding I18nProvider lang over stale global default', async () => {
    globalThis.__NEXT_TRANSLATE__ = {
      lang: 'en',
      namespaces: { common: { languageName: 'English' } },
      config: {},
    }

    const loadLocale = jest.fn(async (lang, ns) => ({
      languageName: `${lang}-${ns}`,
    }))

    const { container } = render(
      <I18nProvider lang="es">
        <DynamicNamespaces namespaces={['common']} dynamic={loadLocale}>
          <Text />
        </DynamicNamespaces>
      </I18nProvider>
    )

    await waitFor(() => expect(container.textContent).toBe('es:es-common'))
    expect(loadLocale).toHaveBeenCalledWith('es', 'common')
  })
})
EOF
